using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Reacções físicas do player a impactos: invencibilidade temporária + knockback
/// ao ser atingido ("TakeHit") e recuo ao bater contra paredes a alta velocidade
/// ("wall bump").
///
/// Extraído de PlayerController_Horse (HorseController2D) ao reorganizar
/// Scripts/ — era a única lógica desse script sem equivalente no sistema novo
/// (PlayerMotor2D / DashAbility / AnimalFormData / PlayerProgress).
///
/// P2: <see cref="TryDamagePlayer"/> é agora o ponto de entrada ÚNICO de dano
/// ao player (usado por EnemyAttackController, ProjectileController e
/// EnemyContactDamage): respeita IsInvulnerable (i-frames), aplica a Defesa
/// da forma actual (AnimalFormData.ApplyDefense — tabela por patamares) e
/// chama TakeHit (invencibilidade + knockback).
/// </summary>
[RequireComponent(typeof(Rigidbody2D), typeof(PlayerMotor2D))]
public class PlayerCombat : MonoBehaviour
{
    [Header("Damage / Invuln")]
    [SerializeField] private float invulnTime = 0.8f;
    [SerializeField] private float knockbackX = 9f;
    [SerializeField] private float knockbackY = 8f;

    [Header("Wall Bump")]
    [SerializeField] private float wallBumpMinSpeed = 10.5f;
    [SerializeField] private float wallBumpRecoil = 6.0f;
    [SerializeField] private float wallBumpStun = 0.08f;

    [Header("Resistência a Knockback (Tarefa #28)")]
    [Tooltip("Limite mínimo do multiplicador de knockback (evita knockback totalmente nulo por acumulação de resistências — forma Resistente + Raiz de Aderência, etc.). Ignorado quando um IKnockbackResistanceProvider concede imunidade total (KnockbackMultiplier == 0).")]
    [Range(0f, 1f)] [SerializeField] private float minKnockbackMultiplier = 0.15f;

    private Rigidbody2D rb;
    private PlayerMotor2D motor;
    private FormSwitcher formSwitcher;
    private IKnockbackResistanceProvider[] knockbackProviders;

    private float invulnTimer;
    private float stunTimer;

    // Tarefa #28 — buff temporário de "Raiz de Aderência" (reduz knockback + derrapagem).
    private float _tempKnockbackMultiplier = 1f;
    private float _tempSkidGripMultiplier = 1f;
    private float _tempGripTimer;

    // Tarefa #28 — imunidade temporária a tipos de dano específicos (ex: Hazard após queda).
    private readonly Dictionary<DamageType, float> _typeImmunityTimers = new Dictionary<DamageType, float>();
    // Cache reutilizável para iterar _typeImmunityTimers em Update sem alocar por frame.
    private readonly List<DamageType> _immunityKeysCache = new List<DamageType>();

    public bool IsInvulnerable => invulnTimer > 0f;

    /// <summary>
    /// Multiplicador aplicado à derrapagem (PlayerMotor2D.skidBrake) enquanto o
    /// buff de "Raiz de Aderência" estiver activo (&gt;= 1 = trava mais rápido
    /// = menos derrapagem); 1 = sem efeito.
    /// </summary>
    public float SkidGripMultiplier => _tempGripTimer > 0f ? _tempSkidGripMultiplier : 1f;

    /// <summary>
    /// Disparado por TryDamagePlayer sempre que o player recebe dano que passa
    /// pelos i-frames (já com Defesa/Escudo aplicados). "info" é a informação
    /// original do golpe, "finalAmount" é o valor de corações realmente
    /// subtraído. UI/VFX/SFX (flash do sprite, som, vibração, screen shake)
    /// devem ligar-se aqui em vez de duplicar lógica de dano — ver auditoria
    /// item 10 ("falta evento de dano").
    /// </summary>
    public event System.Action<DamageInfo, int> OnPlayerDamaged;

    private void Awake()
    {
        rb = GetComponent<Rigidbody2D>();
        motor = GetComponent<PlayerMotor2D>();
        formSwitcher = GetComponent<FormSwitcher>();
        knockbackProviders = GetComponents<IKnockbackResistanceProvider>();
    }

    private void Update()
    {
        if (invulnTimer > 0f)
            invulnTimer -= Time.deltaTime;

        if (stunTimer > 0f)
        {
            stunTimer -= Time.deltaTime;
            if (stunTimer <= 0f) motor.SetMovementLocked(false, this);
        }

        if (_tempGripTimer > 0f)
        {
            _tempGripTimer -= Time.deltaTime;
            if (_tempGripTimer <= 0f)
            {
                _tempGripTimer = 0f;
                _tempKnockbackMultiplier = 1f;
            }
        }

        if (_typeImmunityTimers.Count > 0)
        {
            _immunityKeysCache.Clear();
            foreach (var key in _typeImmunityTimers.Keys) _immunityKeysCache.Add(key);
            foreach (var type in _immunityKeysCache)
            {
                float remaining = _typeImmunityTimers[type] - Time.deltaTime;
                if (remaining <= 0f) _typeImmunityTimers.Remove(type);
                else _typeImmunityTimers[type] = remaining;
            }
        }
    }

    /// <summary>Chama isto quando o player levar dano: aplica invencibilidade + knockback. "knockbackForce" &gt; 0 substitui a força horizontal por defeito (knockbackX).</summary>
    public void TakeHit(Vector2 hitFrom, float knockbackForce = -1f)
    {
        if (invulnTimer > 0f) return;

        invulnTimer = invulnTime;

        float multiplier = ComputeKnockbackMultiplier();

        float dir = (transform.position.x - hitFrom.x) >= 0 ? 1f : -1f;
        float forceX = (knockbackForce > 0f ? knockbackForce : knockbackX) * multiplier;
        float forceY = knockbackY * multiplier;
        rb.velocity = new Vector2(dir * forceX, forceY);

        BeginStun(0.06f);
    }

    /// <summary>
    /// Tarefa #28 — calcula o multiplicador de knockback aplicado a este
    /// player: resistência da forma actual (<see cref="AnimalFormData.knockbackResistance"/>)
    /// × buff temporário de "Raiz de Aderência" × resistências de habilidades
    /// (<see cref="IKnockbackResistanceProvider"/>). Se qualquer provider
    /// devolver exactamente 0, concede imunidade total (ignora
    /// <see cref="minKnockbackMultiplier"/>); caso contrário o resultado é
    /// limitado por baixo a <see cref="minKnockbackMultiplier"/> para evitar
    /// knockback completamente nulo só por acumulação de resistências.
    /// </summary>
    public float ComputeKnockbackMultiplier()
    {
        float multiplier = 1f;

        if (formSwitcher != null && formSwitcher.CurrentForm != null)
            multiplier *= Mathf.Clamp01(formSwitcher.CurrentForm.knockbackResistance);

        multiplier *= Mathf.Max(0f, _tempKnockbackMultiplier);

        bool fullImmunity = false;
        if (knockbackProviders != null)
        {
            foreach (var provider in knockbackProviders)
            {
                float m = provider.KnockbackMultiplier;
                if (m <= 0f) fullImmunity = true;
                multiplier *= Mathf.Max(0f, m);
            }
        }

        if (fullImmunity) return 0f;

        return Mathf.Max(minKnockbackMultiplier, multiplier);
    }

    /// <summary>
    /// Tarefa #28 — aplica o buff temporário do item "Raiz de Aderência":
    /// reduz knockback recebido (knockbackMultiplier, 0-1) e derrapagem
    /// (skidGripMultiplier, &gt;= 1) durante "duration" segundos. Chamado por
    /// <see cref="PlayerItemUser"/> ao usar o item.
    /// </summary>
    public void ApplyTemporaryGripBuff(float knockbackMultiplier, float skidGripMultiplier, float duration)
    {
        _tempKnockbackMultiplier = Mathf.Clamp01(knockbackMultiplier);
        _tempSkidGripMultiplier = Mathf.Max(1f, skidGripMultiplier);
        _tempGripTimer = Mathf.Max(0f, duration);
    }

    /// <summary>
    /// Tarefa #28 — concede imunidade temporária a um tipo de dano específico
    /// (ex: Hazard, por X segundos depois de uma queda). "duration" &lt;= 0
    /// remove a imunidade imediatamente.
    /// </summary>
    public void GrantTemporaryImmunity(DamageType type, float duration)
    {
        if (duration <= 0f) { _typeImmunityTimers.Remove(type); return; }
        _typeImmunityTimers[type] = duration;
    }

    /// <summary>True se o player estiver temporariamente imune a este tipo de dano (ver <see cref="GrantTemporaryImmunity"/>).</summary>
    public bool IsImmuneTo(DamageType type) => _typeImmunityTimers.TryGetValue(type, out var remaining) && remaining > 0f;

    /// <summary>
    /// Ponto de entrada ÚNICO de dano ao player (P2). Respeita i-frames
    /// (IsInvulnerable), aplica a Defesa da forma actual
    /// (AnimalFormData.ApplyDefense) e dispara TakeHit (invuln + knockback).
    /// Devolve false se o dano foi ignorado (invulnerável). Funciona mesmo sem
    /// PlayerCombat/FormSwitcher no player (fallback: dano directo + empurrão).
    ///
    /// Dispara <see cref="OnPlayerDamaged"/> (auditoria item 10) com a info
    /// original + valor final aplicado; a morte continua sinalizada por
    /// PlayerProgress.OnHeartsDepleted (PlayerDeathHandler já está ligado lá).
    /// </summary>
    public static bool TryDamagePlayer(Transform player, DamageInfo info)
    {
        if (player == null)
        {
            if (info.Amount > 0) PlayerProgress.Instance?.Damage(info.Amount);
            return true;
        }

        // Usar GetComponentInParent para suportar hitboxes em GameObjects filho com tag "Player".
        var combat = player.GetComponentInParent<PlayerCombat>();
        if (combat != null && (combat.IsInvulnerable || combat.IsImmuneTo(info.Type))) return false;

        int finalAmount = info.Amount;

        if (!info.IgnoreDefense)
        {
            // Defesa da forma actual (fichas GDD 1-10, por patamares).
            var switcher = player.GetComponentInParent<FormSwitcher>();
            if (switcher != null && switcher.CurrentForm != null)
                finalAmount = switcher.CurrentForm.ApplyDefense(finalAmount);

            // Postura de escudo (ShellGuardAbility — Tartaruga): redução extra.
            var guard = player.GetComponentInParent<ShellGuardAbility>();
            if (guard != null && guard.IsGuarding)
                finalAmount = guard.ApplyGuard(finalAmount);

            // Rolamento (RollAbility — Pangolim): bónus de defesa enquanto a rolar.
            var roll = player.GetComponentInParent<RollAbility>();
            if (roll != null && roll.IsRolling)
                finalAmount = roll.ApplyRollDefense(finalAmount);

            // Coala (Tarefa #7): bónus de defesa enquanto agarrado/a escalar.
            var climb = player.GetComponentInParent<ClimbAbility>();
            if (climb != null && climb.IsClimbing)
                finalAmount = climb.ApplyClimbDefense(finalAmount);

            // Tarefa #28 — Pele Serena (×0.5) e Juramento Difícil/Modo Difícil (×2),
            // por esta ordem, com arredondamento para cima e mínimo de 1 de dano.
            finalAmount = ApplyHealthModifiers(finalAmount);
        }

        // Escudo da Casca Serenna (Tarefa "Itens Consumíveis"): consome o
        // escudo e bloqueia TANTO o dano quanto o knockback deste golpe, se
        // ainda houver dano a aplicar depois de Defesa/ShellGuard. Mortes
        // especiais (info.IgnoreDefense) ignoram o escudo quando o item
        // concedido tiver "shieldIgnoresSpecialDeaths" activo.
        if (finalAmount > 0)
        {
            var consumable = player.GetComponentInParent<PlayerConsumableEffects>();
            if (consumable != null && consumable.TryConsumeShield(info.IgnoreDefense))
                return true;
        }

        // Tomar dano quebra a camuflagem (CamoAbility — P5).
        var camo = player.GetComponentInParent<CamoAbility>();
        if (camo != null && camo.IsCamoActive)
            camo.BreakCamo();

        if (finalAmount > 0)
            PlayerProgress.Instance?.Damage(finalAmount);

        if (combat != null)
        {
            combat.TakeHit(info.SourcePosition, info.Knockback);
            combat.OnPlayerDamaged?.Invoke(info, finalAmount);
        }
        else if (info.Knockback > 0f)
        {
            // Fallback antigo: empurrão directo no Rigidbody2D.
            var rb = player.GetComponent<Rigidbody2D>();
            if (rb != null)
            {
                Vector2 dir = info.KnockbackDir ?? ((Vector2)player.position - info.SourcePosition);
                rb.velocity = (dir.sqrMagnitude > 0.0001f ? dir.normalized : Vector2.right) * info.Knockback;
            }
        }

        return true;
    }

    /// <summary>
    /// Tarefa #28 — aplica Pele Serena (×0.5, se activa) e Juramento Difícil/
    /// Modo Difícil (×2, se activo), por esta ordem, depois da Defesa/Escudo já
    /// aplicados. Arredonda sempre para cima e garante o mínimo de 1 ponto de
    /// vida em qualquer ataque que já causasse dano (&gt; 0). Quando ambos
    /// estão activos, os multiplicadores ×0.5 e ×2 anulam-se matematicamente.
    /// </summary>
    private static int ApplyHealthModifiers(int amount)
    {
        if (amount <= 0) return amount;

        var progress = PlayerProgress.Instance;
        if (progress == null) return amount;

        float result = amount;

        if (progress.IsPeleSerenaActive) result *= 0.5f;
        if (progress.IsHardModeActive) result *= 2f;

        return Mathf.Max(1, Mathf.CeilToInt(result));
    }

    /// <summary>
    /// Overload legado, mantido para não obrigar a alterar todas as chamadas
    /// existentes de uma vez: assume DamageType.Enemy e respeita Defesa/Escudo
    /// normalmente. Novo código (e chamadores que já sabem a origem do dano)
    /// devem preferir <see cref="TryDamagePlayer(Transform, DamageInfo)"/>.
    /// </summary>
    public static bool TryDamagePlayer(Transform player, int amount, Vector2 hitFrom, float knockbackForce = 0f, Vector2? knockbackDir = null)
    {
        return TryDamagePlayer(player, new DamageInfo(amount, DamageType.Enemy, hitFrom, knockbackForce, knockbackDir));
    }

    private void OnCollisionEnter2D(Collision2D col)
    {
        if (motor.IsDashing) return;
        if (col.contactCount == 0) return;

        foreach (var c in col.contacts)
        {
            if (Mathf.Abs(c.normal.x) > 0.7f)
            {
                float speed = Mathf.Abs(rb.velocity.x);
                if (speed >= wallBumpMinSpeed)
                {
                    float recoilDir = Mathf.Sign(c.normal.x);
                    rb.velocity = new Vector2(recoilDir * wallBumpRecoil, rb.velocity.y);
                    BeginStun(wallBumpStun);
                }
                break;
            }
        }
    }

    private void BeginStun(float duration)
    {
        if (duration <= 0f) return;
        stunTimer = Mathf.Max(stunTimer, duration);
        motor.SetMovementLocked(true, this);
    }
}
